import java.util.*;

public class Solution {
    public static long solve(long n, long k) {
        if (k == 0) {
            return 0;
        }
        if (k == 1) {
            long count = 0;
            for (long i = 1; i <= n; i++) {
                if (Integer.bitCount(i) == 1) {
                    count++;
                }
            }
            return count;
        }

        // Precompute the popcount depth for numbers up to n
        // Since k is small (0 <= k <= 5), we can use BFS to find numbers with exact depth k
        // We use a queue to perform BFS and track the depth of each number

        // We use a visited array to track the depth of each number
        // Since n can be up to 1e15, we can't use an array, so we use a HashMap
        Map<Long, Integer> depthMap = new HashMap<>();

        // Start with numbers that have popcount 1 (depth 1)
        Queue<Long> queue = new LinkedList<>();
        for (long i = 1; i <= n; i++) {
            if (Integer.bitCount(i) == 1) {
                queue.add(i);
                depthMap.put(i, 1);
            }
        }

        // BFS to find numbers with depth k
        while (!queue.isEmpty()) {
            long current = queue.poll();
            int currentDepth = depthMap.get(current);

            // If we have reached depth k, we can stop processing
            if (currentDepth == k) {
                continue;
            }

            // Compute the popcount of current
            long popCount = Integer.bitCount(current);

            // If popCount is 0, skip (since it's not a valid number)
            if (popCount == 0) {
                continue;
            }

            // If the next depth is k, add to the count
            if (currentDepth + 1 == k) {
                long count = 0;
                for (long i = 1; i <= n; i++) {
                    if (depthMap.get(i) == k) {
                        count++;
                    }
                }
                return count;
            }

            // If the next depth is less than k, add to the queue
            if (currentDepth + 1 < k) {
                // Compute the popcount of current
                long next = Integer.bitCount(current);
                if (!depthMap.containsKey(next)) {
                    depthMap.put(next, currentDepth + 1);
                    queue.add(next);
                }
            }
        }

        // If no numbers have depth k, return 0
        return 0;
    }
}
